var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......설명은 잘 들었습니다.","JPN":"……説明は聞きました。","ENG":"Thank you for your explanation.","TWN":"……我明白了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다른 세계에서 온 방문자라니...... 정말 믿기 힘든 이야기로군요.","JPN":"別の世界からの訪問者だなんて……実に信じがたい話ですね。","ENG":"Visitors from another world. This is hard to believe.","TWN":"來自另一個世界的訪客……真是個難以相信的說法呢。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그래서 제게 제 4종 침식체 요격을 협조해 달라는 겁니까?","JPN":"それで、僕に第4種侵食体の迎撃を頼みたいと？","ENG":"Are you asking me to help you fight a Category 4 C.O.?","TWN":"所以妳想要我協助你們消滅4級侵蝕體？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 역시 카린 양처럼 요점 정리가 정확하시네요.","JPN":"ハハ、さすが呑み込みが早いのも、カリンさんにそっくりですね。","ENG":"Hah hah. You're as straightforward as Karin.","TWN":"哈哈，果然和卡琳小姐一樣會把握重點啊。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"말씀대로 지금은 한 손이라도 더 필요하니까요.","JPN":"今は猫の手も借りたいところですからね。","ENG":"Yes. We need all the help we can get.","TWN":"就像我剛才說的，我們現在急需人手。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 가벼운 태도는 뭡니까?!","JPN":"その軽々しい態度は何ですか！？","ENG":"What's up with your flippant attitude?","TWN":"這是什麼輕浮的態度？！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신들이야말로 이 세계에 불필요한 재난을 가지고 온 당사자들입니다.","JPN":"あなた方こそ、この世界に災害をもたらした張本人じゃないですか。","ENG":"You've invited an unnecessary disaster into our world.","TWN":"你們是給這個世界帶來不必要災難的罪魁禍首。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그에 대한 자각이 있기는 한 겁니까!","JPN":"その自覚はあるんですか！","ENG":"Do you even feel sorry for that?","TWN":"難道對這點毫無自覺嗎！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그, 그야...... 그렇죠......","JPN":"そ、それは……そうでしたね……","ENG":"W-well... Yes...","TWN":"那，那是……確實……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"역시 그냥 없었던 일로! ......라는 건 어려울까요?","JPN":"やっぱり、なかったことに！　って難しいですかね？","ENG":"Can't we just forget it ever happened? ... We can't, can we?","TWN":"就當作沒發生這種事！……是不可能的吧？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당연하지 않습니까!","JPN":"当たり前じゃないですか！","ENG":"Of course not!","TWN":"這不是廢話嗎！"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"지금도 믿기는 힘들지만 아마 당신이...... 이 세계의 저라고 생각되네요.","JPN":"今も信じられないですが、あなたは多分……この世界の私なんでしょうね。","ENG":"I still can't believe this, but it seems you're another me in this world.","TWN":"雖然現在還是很難相信，不過你似乎……就是另一個世界的我呢。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨 말에 따르면 당신도 델타 세븐의 일원이라고 하더군요.","JPN":"シノンさんから聞いたのですが、あなたもデルタセブンの一員だとか。","ENG":"Shiyoung said you're in Delta Seven.","TWN":"聽時雨小姐說，你也是第七三角洲部隊的成員。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저 역시 저희 세계의 델타 세븐 부대의 일원이었습니다.","JPN":"私も、私たちの世界のデルタセブン所属でした。","ENG":"So am I, of my own world.","TWN":"我也是我們世界裡第七三角洲部隊的成員。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그게 무슨 상관입니까? 그런 건 우연에 불과합니다.","JPN":"何の関係があると？　そんなの、ただの偶然に過ぎません。","ENG":"What's that got to do with this? It's just a coincidence.","TWN":"那又怎樣？那不過是個巧合而已。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"흥미로운 이야기라는 건 인정하지만...... 지금 논의의 주제와는 상관 없는 일입니다.","JPN":"興味深い話なのは認めますが……今の論点とは何ら関係のないことです。","ENG":"I admit that it's intriguing just the same, but it has nothing to do with what we're discussing at the moment.","TWN":"我承認這是一個有趣的故事，但是……這與現在討論的主題無關。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저희 세계의 델타 세븐 대원들은...... 저 하나밖에 남지 않았습니다.","JPN":"私たちの世界のデルタセブンで生き残ったのは……私ひとりだけなんです。","ENG":"In our world... I'm the only one left of Delta Seven.","TWN":"我們世界的第七三角洲部隊成員……只剩下我一個人了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};